const AWS = require('aws-sdk');
const https = require('https');
const { URL } = require('url');

const ddb = new AWS.DynamoDB.DocumentClient({
  maxRetries: 2,
  httpOptions: { timeout: 3000, connectTimeout: 1000 }
});

const {
  ORDERS_TABLE,
  PAYMENT_API_URL,
  PAYMENT_API_KEY,
  PAYMENT_TIMEOUT_MS = '4000',
  DEFAULT_CURRENCY = 'USD'
} = process.env;

function safeJsonParse(s) {
  try {
    return JSON.parse(s);
  } catch {
    return null;
  }
}

function httpRequestJson(urlString, { method = 'POST', headers = {}, body, timeoutMs = 4000 } = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlString);

    const data = body == null ? null : Buffer.from(typeof body === 'string' ? body : JSON.stringify(body));
    const req = https.request(
      {
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: url.pathname + url.search,
        method,
        headers: {
          'content-type': 'application/json',
          ...(data ? { 'content-length': data.length } : {}),
          ...headers
        },
        timeout: timeoutMs
      },
      (res) => {
        let chunks = '';
        res.setEncoding('utf8');
        res.on('data', (d) => (chunks += d));
        res.on('end', () => {
          const parsed = safeJsonParse(chunks);
          resolve({
            statusCode: res.statusCode || 0,
            headers: res.headers || {},
            body: chunks,
            json: parsed
          });
        });
      }
    );

    req.on('timeout', () => {
      req.destroy(new Error('RequestTimeout'));
    });
    req.on('error', reject);

    if (data) req.write(data);
    req.end();
  });
}

function nowIso() {
  return new Date().toISOString();
}

async function updateOrder(orderId, updates) {
  const names = {};
  const values = {};
  const sets = [];

  let i = 0;
  for (const [k, v] of Object.entries(updates || {})) {
    i += 1;
    const nk = `#k${i}`;
    const vk = `:v${i}`;
    names[nk] = k;
    values[vk] = v;
    sets.push(`${nk} = ${vk}`);
  }

  const params = {
    TableName: ORDERS_TABLE,
    Key: { orderId },
    UpdateExpression: `SET ${sets.join(', ')}`,
    ExpressionAttributeNames: names,
    ExpressionAttributeValues: values
  };

  await ddb.update(params).promise();
}

async function processOneOrder(order) {
  const orderId = order.orderId || order.id;
  if (!orderId) throw new Error('MissingOrderId');

  const amount = order.amount;
  const currency = order.currency || DEFAULT_CURRENCY;
  const paymentMethod = order.paymentMethod || order.payment || null;
  const customerId = order.customerId || null;

  await updateOrder(orderId, {
    status: 'PAYMENT_PENDING',
    updatedAt: nowIso()
  });

  const paymentReq = {
    orderId,
    amount,
    currency,
    paymentMethod,
    customerId,
    metadata: order.metadata || {}
  };

  const res = await httpRequestJson(PAYMENT_API_URL, {
    method: 'POST',
    timeoutMs: Number(PAYMENT_TIMEOUT_MS) || 4000,
    headers: {
      authorization: PAYMENT_API_KEY ? `Bearer ${PAYMENT_API_KEY}` : undefined
    },
    body: paymentReq
  });

  const ok = res.statusCode >= 200 && res.statusCode < 300;
  const paymentId = (res.json && (res.json.paymentId || res.json.id)) || null;

  if (ok) {
    await updateOrder(orderId, {
      status: 'PAID',
      paymentId,
      paymentRaw: res.json || res.body,
      updatedAt: nowIso()
    });
    return;
  }

  await updateOrder(orderId, {
    status: 'PAYMENT_FAILED',
    paymentId,
    paymentError: res.json || res.body || `HTTP_${res.statusCode}`,
    updatedAt: nowIso()
  });

  throw new Error(`PaymentFailed_HTTP_${res.statusCode}`);
}

function parseSqsMessageBody(record) {
  const raw = record.body;
  const obj = safeJsonParse(raw);
  if (!obj) return { order: null, raw };

  if (obj.Order) return { order: obj.Order, raw };
  if (obj.order) return { order: obj.order, raw };
  return { order: obj, raw };
}

exports.handler = async (event) => {
  if (!ORDERS_TABLE) throw new Error('Missing env ORDERS_TABLE');
  if (!PAYMENT_API_URL) throw new Error('Missing env PAYMENT_API_URL');

  const records = Array.isArray(event && event.Records) ? event.Records : [];
  const failures = [];

  await Promise.all(
    records.map(async (record) => {
      const messageId = record.messageId || 'unknown';
      try {
        const { order, raw } = parseSqsMessageBody(record);
        if (!order) throw new Error(`InvalidMessageBody: ${raw && raw.slice ? raw.slice(0, 200) : ''}`);
        await processOneOrder(order);
      } catch (err) {
        console.error('Order processing error', {
          messageId,
          error: err && err.message ? err.message : String(err),
          stack: err && err.stack ? err.stack : undefined
        });
        failures.push({ itemIdentifier: messageId });
      }
    })
  );

  return { batchItemFailures: failures };
};